package com.chaobo.scm.supplier.application.score;

import com.chaobo.scm.supplier.application.shared.CommandContext;import com.chaobo.scm.supplier.infrastructure.persistence.score.SupplierScoreMapper;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Component;import java.math.BigDecimal;import java.time.*;import java.util.Set;
@Component public class SupplierScorePeriodTask {private final SupplierScoreApplicationService scores;private final SupplierScoreMapper mapper;public SupplierScorePeriodTask(SupplierScoreApplicationService scores,SupplierScoreMapper mapper){this.scores=scores;this.mapper=mapper;}@Scheduled(cron="${scm.supplier.score-period-cron:0 30 1 1 * *}")public void calculatePreviousMonth(){var period=YearMonth.now().minusMonths(1);var from=period.atDay(1).atStartOfDay().atOffset(ZoneOffset.ofHours(8));var to=period.plusMonths(1).atDay(1).atStartOfDay().atOffset(ZoneOffset.ofHours(8));var context=new CommandContext(0,"SYSTEM",0,null,"score-period-"+period,null,"score-period-"+period,Set.of("supplier:score:calculate","supplier:score:publish"));for(long supplierId:mapper.suppliersWithFacts(from,to)){var result=scores.calculate(supplierId,period,BigDecimal.ZERO,null,context);if(result.status()==1)scores.publish(result.id(),result.version(),context);}}}
